import { useState, useCallback, useRef } from 'react';
import { analyzePassword as apiAnalyze } from '../utils/api';
import zxcvbn from 'zxcvbn';

export function usePasswordAnalyzer() {
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [realtimeStrength, setRealtimeStrength] = useState(null);
  const debounceRef = useRef(null);

  const handlePasswordChange = useCallback((value) => {
    setPassword(value);
    setError(null);

    if (!value) {
      setRealtimeStrength(null);
      return;
    }

    const z = zxcvbn(value);
    setRealtimeStrength({
      score: z.score,
      entropy: Math.log2(z.guesses),
      charsetSize: getCharsetSize(value),
      length: value.length,
    });

    if (debounceRef.current) clearTimeout(debounceRef.current);
    if (value.length >= 1) {
      debounceRef.current = setTimeout(() => {
        analyze(value);
      }, 600);
    }
  }, []); // eslint-disable-line

  const analyze = useCallback(async (pwd) => {
    const target = pwd || password;
    if (!target) return;

    setLoading(true);
    setError(null);

    try {
      const data = await apiAnalyze(target);
      setResult(data.data);
    } catch (err) {
      if (err.response?.data?.error) {
        setError(err.response.data.error);
      } else if (err.code === 'ECONNABORTED' || err.message === 'Network Error') {
        setError('Cannot reach the backend server. Make sure it is running on port 5000.');
      } else {
        setError('Analysis failed. Please try again.');
      }
    } finally {
      setLoading(false);
    }
  }, [password]);

  const reset = useCallback(() => {
    setPassword('');
    setResult(null);
    setError(null);
    setRealtimeStrength(null);
  }, []);

  return {
    password, setPassword: handlePasswordChange,
    showPassword, setShowPassword,
    result, loading, error,
    realtimeStrength,
    analyze: () => analyze(password),
    reset,
  };
}

function getCharsetSize(password) {
  let size = 0;
  if (/[a-z]/.test(password)) size += 26;
  if (/[A-Z]/.test(password)) size += 26;
  if (/\d/.test(password)) size += 10;
  if (/[^a-zA-Z\d]/.test(password)) size += 32;
  return size || 26;
}
